// Engenharia / Cinematic / Zoom Pulse / 16:9 Longos
// Importado pelo Template Studio.
"use client";

import {
  AbsoluteFill,
  Img,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

type EngineeringZoomPulseProps = {
  imageUrl?: string;
  duration?: number;
  minScale?: number;
  maxScale?: number;
  title?: string;
  subtitle?: string;
  projectCode?: string;
  statusText?: string;
  location?: string;
  panelLabel?: string;
  primaryColor?: string;
  secondaryColor?: string;
  accentColor?: string;
  backgroundColor?: string;
  overlayOpacity?: number;
};

export const EngineeringZoomPulse: React.FC<EngineeringZoomPulseProps> = ({
  imageUrl = "https://images.pexels.com/photos/1726310/pexels-photo-1726310.jpeg?auto=compress&cs=tinysrgb&w=1260&h=750&dpr=2",
  duration = 4,
  minScale = 1,
  maxScale = 1.12,
  title = "INSPEÇÃO ESTRUTURAL",
  subtitle = "Análise visual com pulso de aproximação técnica",
  projectCode = "ENG-3024",
  statusText = "MONITORAMENTO ATIVO",
  location = "SETOR B-07",
  panelLabel = "ZOOM PULSE",
  primaryColor = "#22d3ee",
  secondaryColor = "#38bdf8",
  accentColor = "#facc15",
  backgroundColor = "#030712",
  overlayOpacity = 0.82,
}) => {
  const frame = useCurrentFrame();
  const { width, height, fps } = useVideoConfig();

  const isVertical = height > width;
  const cycleFrames = Math.max(1, Math.round(duration * fps));
  const cycleFrame = frame % cycleFrames;

  const halfCycle = cycleFrames / 2;

  const pulseScale =
    cycleFrame <= halfCycle
      ? interpolate(cycleFrame, [0, halfCycle], [minScale, maxScale], {
          extrapolateLeft: "clamp",
          extrapolateRight: "clamp",
        })
      : interpolate(cycleFrame, [halfCycle, cycleFrames], [maxScale, minScale], {
          extrapolateLeft: "clamp",
          extrapolateRight: "clamp",
        });

  const entrance = spring({
    frame,
    fps,
    config: {
      damping: 18,
      stiffness: 85,
      mass: 0.85,
    },
  });

  const scanY = interpolate(frame % 140, [0, 140], [-12, 112]);
  const scanX = interpolate(frame % 180, [0, 180], [-15, 115]);
  const pulseOpacity = interpolate(
    Math.sin((frame / cycleFrames) * Math.PI * 2),
    [-1, 1],
    [0.18, 0.5]
  );

  const hudScale = interpolate(entrance, [0, 1], [0.96, 1]);
  const titleSize = isVertical ? width * 0.055 : height * 0.06;
  const subtitleSize = isVertical ? width * 0.031 : height * 0.028;
  const framePadding = isVertical ? 44 : 58;
  const pipWidth = isVertical ? width * 0.82 : width * 0.46;
  const pipHeight = isVertical ? height * 0.46 : height * 0.58;

  return (
    <AbsoluteFill
      style={{
        backgroundColor,
        overflow: "hidden",
        color: "#e5f7ff",
        fontFamily:
          "Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif",
      }}
    >
      <Img
        src={imageUrl}
        style={{
          position: "absolute",
          inset: 0,
          width: "100%",
          height: "100%",
          objectFit: "cover",
          transform: `scale(${pulseScale})`,
          filter: "contrast(1.15) saturate(0.82) brightness(0.72)",
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          background: `
            linear-gradient(90deg, rgba(3,7,18,0.92), rgba(3,7,18,0.52), rgba(3,7,18,0.88)),
            radial-gradient(circle at 68% 48%, rgba(34,211,238,0.18), transparent 34%),
            radial-gradient(circle at 20% 82%, rgba(250,204,21,0.08), transparent 34%)
          `,
          opacity: overlayOpacity,
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage: `
            linear-gradient(rgba(34,211,238,0.08) 1px, transparent 1px),
            linear-gradient(90deg, rgba(34,211,238,0.08) 1px, transparent 1px),
            linear-gradient(rgba(250,204,21,0.035) 1px, transparent 1px),
            linear-gradient(90deg, rgba(250,204,21,0.035) 1px, transparent 1px)
          `,
          backgroundSize: "38px 38px, 38px 38px, 152px 152px, 152px 152px",
          opacity: 0.9,
        }}
      />

      <div
        style={{
          position: "absolute",
          left: 0,
          right: 0,
          top: `${scanY}%`,
          height: 2,
          background: `linear-gradient(90deg, transparent, ${primaryColor}, transparent)`,
          opacity: 0.36,
          filter: `drop-shadow(0 0 12px ${primaryColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          top: 0,
          bottom: 0,
          left: `${scanX}%`,
          width: 2,
          background: `linear-gradient(180deg, transparent, ${accentColor}, transparent)`,
          opacity: 0.18,
          filter: `drop-shadow(0 0 10px ${accentColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: framePadding,
          border: `1px solid rgba(34,211,238,0.28)`,
          boxShadow: `
            inset 0 0 44px rgba(34,211,238,0.055),
            0 0 52px rgba(0,0,0,0.38)
          `,
          clipPath:
            "polygon(28px 0, calc(100% - 28px) 0, 100% 28px, 100% calc(100% - 28px), calc(100% - 28px) 100%, 28px 100%, 0 calc(100% - 28px), 0 28px)",
          opacity: entrance,
          transform: `scale(${hudScale})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          top: isVertical ? 76 : 62,
          left: isVertical ? 58 : 76,
          right: isVertical ? 58 : 76,
          display: "flex",
          justifyContent: "space-between",
          alignItems: "flex-start",
          gap: 24,
          opacity: entrance,
          transform: `translateY(${interpolate(entrance, [0, 1], [-18, 0])}px)`,
        }}
      >
        <div>
          <div
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: 10,
              padding: "8px 14px",
              border: `1px solid rgba(250,204,21,0.34)`,
              background: "rgba(250,204,21,0.07)",
              color: "rgba(255,255,255,0.82)",
              fontSize: isVertical ? 14 : 13,
              fontWeight: 850,
              letterSpacing: 2.6,
              textTransform: "uppercase",
              clipPath:
                "polygon(0 0, calc(100% - 12px) 0, 100% 12px, 100% 100%, 0 100%)",
            }}
          >
            <span
              style={{
                width: 8,
                height: 8,
                background: accentColor,
                boxShadow: `0 0 12px ${accentColor}`,
              }}
            />
            {panelLabel}
          </div>

          <h1
            style={{
              margin: "20px 0 8px",
              maxWidth: isVertical ? "100%" : width * 0.4,
              color: "white",
              fontSize: titleSize,
              lineHeight: 0.96,
              fontWeight: 950,
              letterSpacing: -1.2,
              textTransform: "uppercase",
              textShadow: `0 0 28px rgba(34,211,238,0.28)`,
            }}
          >
            {title}
          </h1>

          <p
            style={{
              margin: 0,
              maxWidth: isVertical ? "100%" : width * 0.36,
              color: "rgba(226,232,240,0.74)",
              fontSize: subtitleSize,
              lineHeight: 1.34,
            }}
          >
            {subtitle}
          </p>
        </div>

        {!isVertical ? (
          <div
            style={{
              minWidth: 250,
              textAlign: "right",
              borderTop: `2px solid ${primaryColor}`,
              paddingTop: 12,
            }}
          >
            <div
              style={{
                color: primaryColor,
                fontSize: 13,
                fontWeight: 900,
                letterSpacing: 2.8,
                textTransform: "uppercase",
              }}
            >
              {projectCode}
            </div>
            <div
              style={{
                marginTop: 8,
                color: "rgba(255,255,255,0.66)",
                fontSize: 15,
                letterSpacing: 1.7,
                textTransform: "uppercase",
              }}
            >
              {location}
            </div>
          </div>
        ) : null}
      </div>

      <div
        style={{
          position: "absolute",
          width: pipWidth,
          height: pipHeight,
          right: isVertical ? "50%" : 76,
          top: isVertical ? "53%" : "53%",
          transform: isVertical
            ? `translate(50%, -50%) scale(${interpolate(entrance, [0, 1], [0.94, 1])})`
            : `translateY(-50%) scale(${interpolate(entrance, [0, 1], [0.94, 1])})`,
          opacity: entrance,
        }}
      >
        <div
          style={{
            position: "absolute",
            inset: 0,
            border: `1px solid rgba(34,211,238,0.38)`,
            background: "rgba(2,6,23,0.38)",
            boxShadow: `
              inset 0 0 38px rgba(34,211,238,0.07),
              0 0 36px rgba(34,211,238,0.1)
            `,
            clipPath:
              "polygon(22px 0, calc(100% - 22px) 0, 100% 22px, 100% calc(100% - 22px), calc(100% - 22px) 100%, 22px 100%, 0 calc(100% - 22px), 0 22px)",
          }}
        />

        <div
          style={{
            position: "absolute",
            inset: 14,
            overflow: "hidden",
            border: `1px solid rgba(255,255,255,0.1)`,
            clipPath:
              "polygon(16px 0, calc(100% - 16px) 0, 100% 16px, 100% calc(100% - 16px), calc(100% - 16px) 100%, 16px 100%, 0 calc(100% - 16px), 0 16px)",
          }}
        >
          <Img
            src={imageUrl}
            style={{
              width: "100%",
              height: "100%",
              objectFit: "cover",
              transform: `scale(${pulseScale})`,
              filter: "contrast(1.22) saturate(0.78) brightness(0.76)",
            }}
          />

          <div
            style={{
              position: "absolute",
              inset: 0,
              background: `
                linear-gradient(180deg, rgba(3,7,18,0.1), rgba(3,7,18,0.58)),
                radial-gradient(circle at center, rgba(34,211,238,0.06), transparent 54%)
              `,
            }}
          />

          <div
            style={{
              position: "absolute",
              inset: 0,
              backgroundImage: `
                linear-gradient(rgba(34,211,238,0.12) 1px, transparent 1px),
                linear-gradient(90deg, rgba(34,211,238,0.12) 1px, transparent 1px)
              `,
              backgroundSize: "28px 28px",
              opacity: 0.32,
            }}
          />

          <div
            style={{
              position: "absolute",
              left: "50%",
              top: "50%",
              width: isVertical ? 160 : 190,
              height: isVertical ? 160 : 190,
              transform: "translate(-50%, -50%)",
              borderRadius: "50%",
              border: `1px solid rgba(34,211,238,${pulseOpacity})`,
              boxShadow: `0 0 38px rgba(34,211,238,${pulseOpacity * 0.6})`,
            }}
          />

          <div
            style={{
              position: "absolute",
              left: "50%",
              top: "50%",
              width: isVertical ? 96 : 118,
              height: isVertical ? 96 : 118,
              transform: "translate(-50%, -50%)",
              borderRadius: "50%",
              border: `1px dashed rgba(250,204,21,${pulseOpacity + 0.1})`,
            }}
          />

          <div
            style={{
              position: "absolute",
              left: "50%",
              top: "50%",
              width: 1,
              height: isVertical ? 190 : 230,
              background: `linear-gradient(180deg, transparent, ${primaryColor}, transparent)`,
              transform: "translate(-50%, -50%)",
              opacity: 0.38,
            }}
          />

          <div
            style={{
              position: "absolute",
              left: "50%",
              top: "50%",
              width: isVertical ? 210 : 260,
              height: 1,
              background: `linear-gradient(90deg, transparent, ${primaryColor}, transparent)`,
              transform: "translate(-50%, -50%)",
              opacity: 0.38,
            }}
          />

          <div
            style={{
              position: "absolute",
              left: 18,
              top: 18,
              padding: "7px 10px",
              background: "rgba(2,6,23,0.72)",
              border: `1px solid rgba(34,211,238,0.32)`,
              color: primaryColor,
              fontSize: isVertical ? 11 : 12,
              fontWeight: 900,
              letterSpacing: 2,
              textTransform: "uppercase",
            }}
          >
            {statusText}
          </div>

          <div
            style={{
              position: "absolute",
              right: 18,
              bottom: 18,
              padding: "7px 10px",
              background: "rgba(2,6,23,0.72)",
              border: `1px solid rgba(250,204,21,0.32)`,
              color: accentColor,
              fontSize: isVertical ? 11 : 12,
              fontWeight: 900,
              letterSpacing: 2,
              textTransform: "uppercase",
            }}
          >
            ZOOM {pulseScale.toFixed(2)}X
          </div>
        </div>
      </div>

      <div
        style={{
          position: "absolute",
          left: isVertical ? 58 : 76,
          right: isVertical ? 58 : "auto",
          bottom: isVertical ? 70 : 62,
          width: isVertical ? "auto" : width * 0.34,
          display: "grid",
          gridTemplateColumns: isVertical ? "1fr" : "1fr 1fr",
          gap: 12,
          opacity: entrance,
          transform: `translateY(${interpolate(entrance, [0, 1], [18, 0])}px)`,
        }}
      >
        <div
          style={{
            padding: "15px 16px",
            background: "rgba(2,6,23,0.72)",
            border: `1px solid rgba(34,211,238,0.24)`,
            borderLeft: `3px solid ${primaryColor}`,
            clipPath:
              "polygon(0 0, calc(100% - 13px) 0, 100% 13px, 100% 100%, 0 100%)",
          }}
        >
          <div
            style={{
              color: primaryColor,
              fontSize: 12,
              fontWeight: 900,
              letterSpacing: 2.2,
              textTransform: "uppercase",
              marginBottom: 8,
            }}
          >
            {projectCode}
          </div>
          <div
            style={{
              color: "rgba(255,255,255,0.78)",
              fontSize: isVertical ? 17 : 16,
              fontWeight: 800,
              letterSpacing: 1,
              textTransform: "uppercase",
            }}
          >
            {location}
          </div>
        </div>

        <div
          style={{
            padding: "15px 16px",
            background: "rgba(2,6,23,0.72)",
            border: `1px solid rgba(250,204,21,0.24)`,
            borderLeft: `3px solid ${accentColor}`,
            clipPath:
              "polygon(0 0, calc(100% - 13px) 0, 100% 13px, 100% 100%, 0 100%)",
          }}
        >
          <div
            style={{
              color: accentColor,
              fontSize: 12,
              fontWeight: 900,
              letterSpacing: 2.2,
              textTransform: "uppercase",
              marginBottom: 8,
            }}
          >
            PULSE RANGE
          </div>
          <div
            style={{
              color: "rgba(255,255,255,0.78)",
              fontSize: isVertical ? 17 : 16,
              fontWeight: 800,
              letterSpacing: 1,
              textTransform: "uppercase",
            }}
          >
            {minScale.toFixed(2)}X / {maxScale.toFixed(2)}X
          </div>
        </div>
      </div>

      {[
        { top: 28, left: 28, borderWidth: "2px 0 0 2px" },
        { top: 28, right: 28, borderWidth: "2px 2px 0 0" },
        { bottom: 28, left: 28, borderWidth: "0 0 2px 2px" },
        { bottom: 28, right: 28, borderWidth: "0 2px 2px 0" },
      ].map((corner, index) => (
        <div
          key={index}
          style={{
            position: "absolute",
            width: 42,
            height: 42,
            borderStyle: "solid",
            borderColor: "rgba(34,211,238,0.58)",
            ...corner,
          }}
        />
      ))}
    </AbsoluteFill>
  );
};

export default EngineeringZoomPulse;

