          position: "absolute",
          inset: padY,
          border: "1px solid rgba(34,211,238,.28)",
          boxShadow: "inset 0 0 0 1px rgba(251,191,36,.12)",
          clipPath:
            "polygon(0 14px, 14px 0, calc(100% - 14px) 0, 100% 14px, 100% calc(100% - 14px), calc(100% - 14px) 100%, 14px 100%, 0 calc(100% - 14px))",
          opacity: enter,
        }}
      />
      <div
        style={{
