  statusText?: string;
  location?: string;
  projectCode?: string;
  primaryColor?: string;
  secondaryColor?: string;
  accentColor?: string;
  backgroundColor?: string;
  progress?: number;
  label?: string;
  suffix?: string;
  durationInFrames?: string;
};

