// Engenharia / Image e Media / Picture in Picture / 16:9 Longos
// Importado pelo Template Studio.
"use client";

import {
  AbsoluteFill,
  Img,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

type EngineeringPictureInPictureProps = {
  title?: string;
  subtitle?: string;
  mainLabel?: string;
  pipTitle?: string;
  pipSubtitle?: string;
  pipLabel?: string;
  panelLabel?: string;
  statusText?: string;
  location?: string;
  projectCode?: string;
  coordinates?: string;
  mainImageUrl?: string;
  pipImageUrl?: string;
  primaryColor?: string;
  secondaryColor?: string;
  accentColor?: string;
  backgroundColor?: string;
};

export default function EngineeringPictureInPicture({
  title = "ANÁLISE ESTRUTURAL",
  subtitle = "Visualização técnica do setor monitorado",
  mainLabel = "ÁREA PRINCIPAL",
  pipTitle = "MAPA TÉCNICO",
  pipSubtitle = "Localização da intervenção",
  pipLabel = "PIP VIEW",
  panelLabel = "ENGINEERING FEED",
  statusText = "MONITORAMENTO ATIVO",
  location = "SETOR A-03",
  projectCode = "ENG-3142",
  coordinates = "30°02' S / 51°13' W",
  mainImageUrl = "",
  pipImageUrl = "",
  primaryColor = "#22d3ee",
  secondaryColor = "#0f766e",
  accentColor = "#facc15",
  backgroundColor = "#05070d",
}: EngineeringPictureInPictureProps) {
  const frame = useCurrentFrame();
  const { fps, width, height } = useVideoConfig();

  const isVertical = height > width;

  const enter = spring({
    frame,
    fps,
    config: {
      damping: 18,
      stiffness: 82,
      mass: 0.85,
    },
  });

  const pipEnter = spring({
    frame: Math.max(frame - 18, 0),
    fps,
    config: {
      damping: 14,
      stiffness: 115,
      mass: 0.8,
    },
  });

  const scanX = interpolate(frame % 140, [0, 140], [-12, 112]);
  const scanY = interpolate(frame % 120, [0, 120], [-10, 110]);
  const pulse = 1 + Math.sin(frame / 14) * 0.018;
  const radarRotation = (frame * 1.35) % 360;
  const pipGlow = 0.28 + Math.sin(frame / 12) * 0.08;

  const mainInset = isVertical ? 34 : 48;
  const headerTop = isVertical ? 54 : 44;
  const pipWidth = isVertical ? width * 0.78 : width * 0.27;
  const pipHeight = isVertical ? pipWidth * 0.66 : pipWidth * 0.64;
  const pipRight = isVertical ? width * 0.11 : 56;
  const pipBottom = isVertical ? 72 : 52;

  const titleSize = isVertical ? width * 0.055 : height * 0.058;
  const subtitleSize = isVertical ? width * 0.032 : height * 0.028;

  return (
    <AbsoluteFill
      style={{
        backgroundColor,
        overflow: "hidden",
        color: "#e5f7ff",
        fontFamily:
          "Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif",
      }}
    >
      <div
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage: `
            linear-gradient(rgba(34,211,238,0.07) 1px, transparent 1px),
            linear-gradient(90deg, rgba(34,211,238,0.07) 1px, transparent 1px),
            linear-gradient(rgba(250,204,21,0.035) 1px, transparent 1px),
            linear-gradient(90deg, rgba(250,204,21,0.035) 1px, transparent 1px)
          `,
          backgroundSize: "38px 38px, 38px 38px, 152px 152px, 152px 152px",
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          background: `
            radial-gradient(circle at 72% 78%, rgba(34,211,238,0.13), transparent 30%),
            radial-gradient(circle at 18% 20%, rgba(250,204,21,0.08), transparent 28%),
            linear-gradient(135deg, rgba(2,6,23,0.35), rgba(3,7,18,0.95))
          `,
        }}
      />

      <div
        style={{
          position: "absolute",
          left: `${scanX}%`,
          top: 0,
          bottom: 0,
          width: 2,
          background: `linear-gradient(180deg, transparent, ${primaryColor}, transparent)`,
          opacity: 0.22,
          filter: `drop-shadow(0 0 12px ${primaryColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          left: 0,
          right: 0,
          top: `${scanY}%`,
          height: 2,
          background: `linear-gradient(90deg, transparent, ${accentColor}, transparent)`,
          opacity: 0.18,
          filter: `drop-shadow(0 0 10px ${accentColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: mainInset,
          opacity: enter,
          transform: `scale(${interpolate(enter, [0, 1], [1.035, 1])})`,
          background: "rgba(8,13,24,0.55)",
          border: `1px solid rgba(34,211,238,0.25)`,
          clipPath:
            "polygon(28px 0, calc(100% - 28px) 0, 100% 28px, 100% calc(100% - 28px), calc(100% - 28px) 100%, 28px 100%, 0 calc(100% - 28px), 0 28px)",
          boxShadow: `
            inset 0 0 60px rgba(34,211,238,0.06),
            0 0 70px rgba(0,0,0,0.45)
          `,
          overflow: "hidden",
        }}
      >
        {mainImageUrl ? (
          <Img
            src={mainImageUrl}
            style={{
              position: "absolute",
              inset: 0,
              width: "100%",
              height: "100%",
              objectFit: "cover",
              opacity: 0.72,
              filter: "contrast(1.12) saturate(0.85) brightness(0.72)",
            }}
          />
        ) : (
          <div
            style={{
              position: "absolute",
              inset: 0,
              background: `
                linear-gradient(135deg, rgba(15,23,42,0.92), rgba(2,6,23,0.96)),
                repeating-linear-gradient(45deg, rgba(34,211,238,0.08) 0px, rgba(34,211,238,0.08) 1px, transparent 1px, transparent 18px)
              `,
            }}
          />
        )}

        <div
          style={{
            position: "absolute",
            inset: 0,
            background: `
              linear-gradient(90deg, rgba(2,6,23,0.92) 0%, rgba(2,6,23,0.45) 46%, rgba(2,6,23,0.82) 100%),
              radial-gradient(circle at 62% 48%, rgba(34,211,238,0.18), transparent 34%)
            `,
          }}
        />

        <div
          style={{
            position: "absolute",
            inset: 0,
            backgroundImage: `
              linear-gradient(rgba(34,211,238,0.08) 1px, transparent 1px),
              linear-gradient(90deg, rgba(34,211,238,0.08) 1px, transparent 1px)
            `,
            backgroundSize: "52px 52px",
            opacity: 0.62,
          }}
        />

        <div
          style={{
            position: "absolute",
            top: headerTop,
            left: isVertical ? 36 : 46,
            right: isVertical ? 36 : 46,
          }}
        >
          <div
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: 10,
              padding: "8px 14px",
              background: "rgba(2,6,23,0.72)",
              border: `1px solid rgba(34,211,238,0.36)`,
              color: "rgba(255,255,255,0.78)",
              fontSize: isVertical ? 14 : 13,
              fontWeight: 900,
              letterSpacing: 2.5,
              textTransform: "uppercase",
              clipPath:
                "polygon(0 0, calc(100% - 12px) 0, 100% 12px, 100% 100%, 12px 100%, 0 calc(100% - 12px))",
            }}
          >
            <span
              style={{
                width: 8,
                height: 8,
                background: accentColor,
                boxShadow: `0 0 12px ${accentColor}`,
              }}
            />
            {panelLabel}
          </div>

          <h1
            style={{
              margin: "20px 0 8px",
              maxWidth: isVertical ? "100%" : width * 0.42,
              color: "white",
              fontSize: titleSize,
              lineHeight: 0.96,
              fontWeight: 950,
              letterSpacing: -1.3,
              textTransform: "uppercase",
              textShadow: `0 0 28px rgba(34,211,238,0.28)`,
            }}
          >
            {title}
          </h1>

          <p
            style={{
              margin: 0,
              maxWidth: isVertical ? "100%" : width * 0.38,
              color: "rgba(226,232,240,0.72)",
              fontSize: subtitleSize,
              lineHeight: 1.35,
            }}
          >
            {subtitle}
          </p>
        </div>

        <div
          style={{
            position: "absolute",
            left: isVertical ? 36 : 46,
            bottom: isVertical ? pipHeight + 110 : 42,
            width: isVertical ? "calc(100% - 72px)" : width * 0.32,
            padding: "15px 17px",
            background: "rgba(2,6,23,0.7)",
            border: `1px solid rgba(34,211,238,0.24)`,
            borderLeft: `3px solid ${primaryColor}`,
            clipPath:
              "polygon(0 0, calc(100% - 16px) 0, 100% 16px, 100% 100%, 0 100%)",
          }}
        >
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              gap: 16,
              color: "rgba(255,255,255,0.66)",
              fontSize: isVertical ? 13 : 12,
              fontWeight: 850,
              letterSpacing: 2,
              textTransform: "uppercase",
              marginBottom: 10,
            }}
          >
            <span>{projectCode}</span>
            <span>{mainLabel}</span>
          </div>

          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              gap: 16,
              color: "white",
              fontSize: isVertical ? 17 : 16,
              fontWeight: 800,
              letterSpacing: 1.2,
              textTransform: "uppercase",
            }}
          >
            <span>{location}</span>
            <span style={{ color: accentColor }}>{statusText}</span>
          </div>
        </div>

        <div
          style={{
            position: "absolute",
            right: pipRight - mainInset,
            bottom: pipBottom - mainInset,
            width: pipWidth,
            height: pipHeight,
            transform: `scale(${pipEnter}) translateY(${interpolate(
              pipEnter,
              [0, 1],
              [34, 0]
            )}px)`,
            transformOrigin: "bottom right",
            opacity: pipEnter,
            background: "rgba(3,7,18,0.9)",
            border: `1px solid rgba(34,211,238,0.58)`,
            boxShadow: `
              0 0 0 1px rgba(250,204,21,0.08),
              0 0 38px rgba(34,211,238,${pipGlow}),
              0 20px 50px rgba(0,0,0,0.56)
            `,
            clipPath:
              "polygon(22px 0, 100% 0, 100% calc(100% - 22px), calc(100% - 22px) 100%, 0 100%, 0 22px)",
            overflow: "hidden",
          }}
        >
          {pipImageUrl ? (
            <Img
              src={pipImageUrl}
              style={{
                position: "absolute",
                inset: 0,
                width: "100%",
                height: "100%",
                objectFit: "cover",
                opacity: 0.82,
                filter: "contrast(1.22) saturate(0.85) brightness(0.78)",
              }}
            />
          ) : (
            <div
              style={{
                position: "absolute",
                inset: 0,
                background: `
                  radial-gradient(circle at 50% 50%, rgba(34,211,238,0.22), transparent 34%),
                  linear-gradient(135deg, rgba(8,47,73,0.84), rgba(2,6,23,0.96))
                `,
              }}
            />
          )}

          <div
            style={{
              position: "absolute",
              inset: 0,
              backgroundImage: `
                linear-gradient(rgba(34,211,238,0.16) 1px, transparent 1px),
                linear-gradient(90deg, rgba(34,211,238,0.16) 1px, transparent 1px)
              `,
              backgroundSize: "28px 28px",
              opacity: 0.76,
            }}
          />

          <div
            style={{
              position: "absolute",
              inset: 0,
              background: `
                linear-gradient(180deg, rgba(2,6,23,0.28), rgba(2,6,23,0.88)),
                radial-gradient(circle at 54% 52%, transparent 0%, transparent 28%, rgba(2,6,23,0.44) 29%, transparent 31%)
              `,
