export default function EngineeringPictureInPicture({
  title = "ANÁLISE ESTRUTURAL",
  subtitle = "Visualização técnica do setor monitorado",
  mainLabel = "ÁREA PRINCIPAL",
  pipTitle = "MAPA TÉCNICO",
  pipSubtitle = "Localização da intervenção",
  pipLabel = "PIP VIEW",
  panelLabel = "ENGINEERING FEED",
  statusText = "MONITORAMENTO ATIVO",
  location = "SETOR A-03",
  projectCode = "ENG-3142",
  coordinates = "30°02' S / 51°13' W",
  mainImageUrl = "",
  pipImageUrl = "",
  primaryColor = "#22d3ee",
  secondaryColor = "#0f766e",
  accentColor = "#facc15",
  backgroundColor = "#05070d",
