  const scanX = interpolate(frame % 140, [0, 140], [-12, 112]);
  const scanY = interpolate(frame % 120, [0, 120], [-10, 110]);
  const pulse = 1 + Math.sin(frame / 14) * 0.018;
  const radarRotation = (frame * 1.35) % 360;
  const pipGlow = 0.28 + Math.sin(frame / 12) * 0.08;

  const mainInset = isVertical ? 34 : 48;
  const headerTop = isVertical ? 54 : 44;
