        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          background: `
            radial-gradient(circle at 72% 78%, rgba(34,211,238,0.13), transparent 30%),
            radial-gradient(circle at 18% 20%, rgba(250,204,21,0.08), transparent 28%),
            linear-gradient(135deg, rgba(2,6,23,0.35), rgba(3,7,18,0.95))
