            style={{
              position: "absolute",
              inset: 0,
              background: `
                linear-gradient(135deg, rgba(15,23,42,0.92), rgba(2,6,23,0.96)),
                repeating-linear-gradient(45deg, rgba(34,211,238,0.08) 0px, rgba(34,211,238,0.08) 1px, transparent 1px, transparent 18px)
              `,
            }}
          />
        )}

        <div
          style={{
            position: "absolute",
            inset: 0,
            background: `
              linear-gradient(90deg, rgba(2,6,23,0.92) 0%, rgba(2,6,23,0.45) 46%, rgba(2,6,23,0.82) 100%),
              radial-gradient(circle at 62% 48%, rgba(34,211,238,0.18), transparent 34%)
