        >
          <div
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: 10,
              padding: "8px 14px",
              background: "rgba(2,6,23,0.72)",
              border: `1px solid rgba(34,211,238,0.36)`,
              color: "rgba(255,255,255,0.78)",
              fontSize: isVertical ? 14 : 13,
              fontWeight: 900,
              letterSpacing: 2.5,
