            border: `1px solid rgba(34,211,238,0.58)`,
            boxShadow: `
              0 0 0 1px rgba(250,204,21,0.08),
              0 0 38px rgba(34,211,238,${pipGlow}),
              0 20px 50px rgba(0,0,0,0.56)
            `,
            clipPath:
              "polygon(22px 0, 100% 0, 100% calc(100% - 22px), calc(100% - 22px) 100%, 0 100%, 0 22px)",
            overflow: "hidden",
          }}
        >
          {pipImageUrl ? (
            <Img
              src={pipImageUrl}
              style={{
                position: "absolute",
                inset: 0,
                width: "100%",
                height: "100%",
                objectFit: "cover",
                opacity: 0.82,
                filter: "contrast(1.22) saturate(0.85) brightness(0.78)",
              }}
            />
          ) : (
            <div
              style={{
                position: "absolute",
                inset: 0,
                background: `
                  radial-gradient(circle at 50% 50%, rgba(34,211,238,0.22), transparent 34%),
