          />

          <div
            style={{
              position: "absolute",
              left: "50%",
              top: "52%",
              width: 12,
              height: 12,
              transform: "translate(-50%, -50%) rotate(45deg)",
              background: accentColor,
              boxShadow: `0 0 18px ${accentColor}`,
