            }}
          >
            <span
              style={{
                color: primaryColor,
                fontSize: isVertical ? 11 : 10,
                fontWeight: 900,
                letterSpacing: 2,
                textTransform: "uppercase",
              }}
            >
              {pipLabel}
            </span>

            <span
              style={{
                color: accentColor,
                fontSize: isVertical ? 11 : 10,
                fontWeight: 900,
                letterSpacing: 1.8,
                textTransform: "uppercase",
