// Engenharia / Image e Media / Comparison Slider / 16:9 Longos
// Importado pelo Template Studio.
"use client";

import {
  AbsoluteFill,
  Img,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

type EngineeringImageComparisonSliderProps = {
  title?: string;
  subtitle?: string;
  beforeLabel?: string;
  afterLabel?: string;
  beforeImageUrl?: string;
  afterImageUrl?: string;
  dividerStart?: number | string;
  dividerEnd?: number | string;
  durationInFrames?: number | string;
  projectCode?: string;
  statusText?: string;
  location?: string;
  panelLabel?: string;
  primaryColor?: string;
  secondaryColor?: string;
  accentColor?: string;
  backgroundColor?: string;
};

const toNumber = (value: unknown, fallback: number) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const clamp = (value: number, min: number, max: number) => {
  return Math.min(Math.max(value, min), max);
};

export default function EngineeringImageComparisonSlider({
  title = "ANTES E DEPOIS ESTRUTURAL",
  subtitle = "Comparativo técnico da intervenção executiva",
  beforeLabel = "ANTES",
  afterLabel = "DEPOIS",
  beforeImageUrl = "",
  afterImageUrl = "",
  dividerStart = 8,
  dividerEnd = 92,
  durationInFrames = 110,
  projectCode = "ENG-3057",
  statusText = "COMPARATIVO VALIDADO",
  location = "SETOR B-04",
  panelLabel = "STRUCTURAL ANALYSIS",
  primaryColor = "#22d3ee",
  secondaryColor = "#38bdf8",
  accentColor = "#facc15",
  backgroundColor = "#030712",
}: EngineeringImageComparisonSliderProps) {
  const frame = useCurrentFrame();
  const { width, height, fps } = useVideoConfig();

  const isVertical = height > width;
  const safeDuration = Math.max(1, toNumber(durationInFrames, 110));
  const start = clamp(toNumber(dividerStart, 8), 0, 100);
  const end = clamp(toNumber(dividerEnd, 92), 0, 100);

  const entrance = spring({
    frame,
    fps,
    config: {
      damping: 18,
      stiffness: 92,
      mass: 0.85,
    },
  });

  const dividerPercent = interpolate(frame, [10, safeDuration], [start, end], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  const scanY = interpolate(frame % 150, [0, 150], [-12, 112]);
  const scanX = interpolate(frame % 130, [0, 130], [-10, 110]);
  const pulse = 1 + Math.sin(frame / 14) * 0.015;

  const stageWidth = isVertical ? width * 0.86 : width * 0.82;
  const stageHeight = isVertical ? height * 0.58 : height * 0.68;

  const titleSize = isVertical ? width * 0.053 : height * 0.055;
  const subtitleSize = isVertical ? width * 0.031 : height * 0.027;
  const labelSize = isVertical ? width * 0.03 : height * 0.027;

  return (
    <AbsoluteFill
      style={{
        backgroundColor,
        overflow: "hidden",
        color: "#e5f7ff",
        fontFamily:
          "Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif",
      }}
    >
      <div
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage: `
            linear-gradient(rgba(34,211,238,0.075) 1px, transparent 1px),
            linear-gradient(90deg, rgba(34,211,238,0.075) 1px, transparent 1px),
            linear-gradient(rgba(250,204,21,0.035) 1px, transparent 1px),
            linear-gradient(90deg, rgba(250,204,21,0.035) 1px, transparent 1px)
          `,
          backgroundSize: "38px 38px, 38px 38px, 152px 152px, 152px 152px",
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          background: `
            radial-gradient(circle at 62% 48%, rgba(34,211,238,0.16), transparent 34%),
            radial-gradient(circle at 18% 82%, rgba(250,204,21,0.08), transparent 32%),
            linear-gradient(135deg, rgba(2,6,23,0.44), rgba(3,7,18,0.96))
          `,
        }}
      />

      <div
        style={{
          position: "absolute",
          left: 0,
          right: 0,
          top: `${scanY}%`,
          height: 2,
          background: `linear-gradient(90deg, transparent, ${primaryColor}, transparent)`,
          opacity: 0.32,
          filter: `drop-shadow(0 0 12px ${primaryColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          top: 0,
          bottom: 0,
          left: `${scanX}%`,
          width: 2,
          background: `linear-gradient(180deg, transparent, ${accentColor}, transparent)`,
          opacity: 0.16,
          filter: `drop-shadow(0 0 10px ${accentColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          top: isVertical ? 58 : 46,
          left: isVertical ? 48 : 70,
          right: isVertical ? 48 : 70,
          display: "flex",
          justifyContent: "space-between",
          alignItems: "flex-start",
          gap: 24,
          opacity: entrance,
          transform: `translateY(${interpolate(entrance, [0, 1], [-18, 0])}px)`,
        }}
      >
        <div>
          <div
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: 10,
              padding: "8px 14px",
              border: `1px solid rgba(250,204,21,0.36)`,
              background: "rgba(250,204,21,0.065)",
              color: "rgba(255,255,255,0.78)",
              fontSize: isVertical ? 14 : 13,
              fontWeight: 850,
              letterSpacing: 2.4,
              textTransform: "uppercase",
              clipPath:
                "polygon(0 0, calc(100% - 12px) 0, 100% 12px, 100% 100%, 12px 100%, 0 calc(100% - 12px))",
            }}
          >
            <span
              style={{
                width: 8,
                height: 8,
                background: accentColor,
                boxShadow: `0 0 12px ${accentColor}`,
              }}
            />
            {panelLabel}
          </div>

          <h1
            style={{
              margin: "20px 0 8px",
              maxWidth: isVertical ? "100%" : width * 0.48,
              color: "white",
              fontSize: titleSize,
              lineHeight: 0.98,
              fontWeight: 950,
              letterSpacing: -1.3,
              textTransform: "uppercase",
              textShadow: `0 0 26px rgba(34,211,238,0.26)`,
            }}
          >
            {title}
          </h1>

          <p
            style={{
              margin: 0,
              maxWidth: isVertical ? "100%" : width * 0.42,
              color: "rgba(226,232,240,0.72)",
              fontSize: subtitleSize,
              lineHeight: 1.35,
            }}
          >
            {subtitle}
          </p>
        </div>

        {!isVertical ? (
          <div
            style={{
              minWidth: 250,
              textAlign: "right",
              borderTop: `2px solid ${primaryColor}`,
              paddingTop: 12,
            }}
          >
            <div
              style={{
                color: primaryColor,
                fontSize: 13,
                fontWeight: 900,
                letterSpacing: 2.8,
                textTransform: "uppercase",
              }}
            >
              {projectCode}
            </div>
            <div
              style={{
                marginTop: 8,
                color: "rgba(255,255,255,0.64)",
                fontSize: 15,
                fontWeight: 750,
                letterSpacing: 1.6,
                textTransform: "uppercase",
              }}
            >
              {location}
            </div>
          </div>
        ) : null}
      </div>

      <div
        style={{
          position: "absolute",
          width: stageWidth,
          height: stageHeight,
          left: "50%",
          top: isVertical ? "54%" : "56%",
          transform: `translate(-50%, -50%) scale(${interpolate(
            entrance,
            [0, 1],
            [0.95, 1]
          )})`,
          opacity: entrance,
        }}
      >
        <div
          style={{
            position: "absolute",
            inset: -18,
            border: `1px solid rgba(34,211,238,0.28)`,
            background: "rgba(8,13,24,0.42)",
