// Engenharia / Image e Media / Comparison Slider / 9:16 Shorts
// Importado pelo Template Studio.
"use client";

import {
  AbsoluteFill,
  Img,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

type EngineeringImageComparisonSliderProps = {
  title?: string;
  subtitle?: string;
  beforeLabel?: string;
  afterLabel?: string;
  beforeImageUrl?: string;
  afterImageUrl?: string;
  dividerStart?: number | string;
  dividerEnd?: number | string;
  durationInFrames?: number | string;
  projectCode?: string;
  statusText?: string;
  location?: string;
  panelLabel?: string;
  primaryColor?: string;
  secondaryColor?: string;
  accentColor?: string;
  backgroundColor?: string;
};

const toNumber = (value: unknown, fallback: number) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const clamp = (value: number, min: number, max: number) => {
  return Math.min(Math.max(value, min), max);
};

export default function EngineeringImageComparisonSlider({
  title = "ANTES E DEPOIS ESTRUTURAL",
  subtitle = "Comparativo técnico da intervenção executiva",
  beforeLabel = "ANTES",
  afterLabel = "DEPOIS",
  beforeImageUrl = "",
  afterImageUrl = "",
  dividerStart = 8,
  dividerEnd = 92,
  durationInFrames = 110,
  projectCode = "ENG-3057",
  statusText = "COMPARATIVO VALIDADO",
  location = "SETOR B-04",
  panelLabel = "STRUCTURAL ANALYSIS",
  primaryColor = "#22d3ee",
  secondaryColor = "#38bdf8",
  accentColor = "#facc15",
  backgroundColor = "#030712",
