            boxShadow: `
              inset 0 0 42px rgba(34,211,238,0.055),
              0 0 70px rgba(0,0,0,0.55)
            `,
            clipPath:
              "polygon(24px 0, calc(100% - 24px) 0, 100% 24px, 100% calc(100% - 24px), calc(100% - 24px) 100%, 24px 100%, 0 calc(100% - 24px), 0 24px)",
          }}
