        <div
          style={{
            position: "absolute",
            inset: 0,
            overflow: "hidden",
            background: "rgba(2,6,23,0.88)",
            border: `1px solid rgba(148,163,184,0.16)`,
            clipPath:
              "polygon(22px 0, calc(100% - 22px) 0, 100% 22px, 100% calc(100% - 22px), calc(100% - 22px) 100%, 22px 100%, 0 calc(100% - 22px), 0 22px)",
