// Engenharia / Image e Media / Masonry Gallery / 16:9 Longos
// Importado pelo Template Studio.
"use client";

import {
  AbsoluteFill,
  Img,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

type EngineeringMasonryBlock = {
  title?: string;
  subtitle?: string;
  metric?: string;
  tag?: string;
  imageUrl?: string;
  heightPct?: number;
  delay?: number;
  accentColor?: string;
};

type EngineeringMasonryGalleryProps = {
  title?: string;
  subtitle?: string;
  projectCode?: string;
  statusText?: string;
  location?: string;
  panelLabel?: string;
  blocks?: EngineeringMasonryBlock[];
  primaryColor?: string;
  secondaryColor?: string;
  accentColor?: string;
  backgroundColor?: string;
};

const defaultBlocks: EngineeringMasonryBlock[] = [
  {
    title: "FUNDAÇÃO",
    subtitle: "Base estrutural",
    metric: "42%",
    tag: "ETAPA 01",
    heightPct: 44,
    delay: 0,
    accentColor: "#22d3ee",
  },
  {
    title: "ARMADURA",
    subtitle: "Malha principal",
    metric: "68%",
    tag: "ETAPA 02",
    heightPct: 54,
    delay: 6,
    accentColor: "#facc15",
  },
  {
    title: "CONCRETO",
    subtitle: "Cura técnica",
    metric: "75%",
    tag: "ETAPA 03",
    heightPct: 58,
    delay: 3,
    accentColor: "#38bdf8",
  },
  {
    title: "PILARES",
    subtitle: "Alinhamento vertical",
    metric: "81%",
    tag: "ETAPA 04",
    heightPct: 40,
    delay: 9,
    accentColor: "#facc15",
  },
  {
    title: "VIGAS",
    subtitle: "Travamento superior",
    metric: "63%",
    tag: "ETAPA 05",
    heightPct: 42,
    delay: 5,
    accentColor: "#22d3ee",
  },
  {
    title: "LAJE",
    subtitle: "Plano executivo",
    metric: "92%",
    tag: "ETAPA 06",
    heightPct: 56,
    delay: 11,
    accentColor: "#38bdf8",
  },
];

export default function EngineeringMasonryGallery({
  title = "MAPA DE EXECUÇÃO",
  subtitle = "Galeria técnica de etapas estruturais",
  projectCode = "ENG-3084",
  statusText = "MONITORAMENTO ATIVO",
  location = "SETOR B / CANTEIRO 04",
  panelLabel = "STRUCTURAL GALLERY",
  blocks = defaultBlocks,
  primaryColor = "#22d3ee",
  secondaryColor = "#0f766e",
  accentColor = "#facc15",
  backgroundColor = "#040812",
}: EngineeringMasonryGalleryProps) {
  const frame = useCurrentFrame();
  const { fps, width, height } = useVideoConfig();

  const isVertical = height > width;
  const columnCount = isVertical ? 2 : 3;
  const safeBlocks = blocks.length > 0 ? blocks : defaultBlocks;

  const columns = Array.from({ length: columnCount }, () => [] as EngineeringMasonryBlock[]);
  safeBlocks.forEach((block, index) => {
    columns[index % columnCount].push(block);
  });

  const entrance = spring({
    frame,
    fps,
    config: {
      damping: 18,
      stiffness: 86,
      mass: 0.8,
    },
  });

  const scanY = interpolate(frame % 150, [0, 150], [-12, 112]);
  const scanX = interpolate(frame % 170, [0, 170], [-15, 115]);

  const framePadding = isVertical ? 42 : 62;
  const headerTop = isVertical ? 48 : 42;
  const titleSize = isVertical ? width * 0.052 : height * 0.055;
  const subtitleSize = isVertical ? width * 0.03 : height * 0.028;
  const cardGap = isVertical ? 14 : 18;

  return (
    <AbsoluteFill
      style={{
        backgroundColor,
        overflow: "hidden",
        color: "#e5f7ff",
        fontFamily:
          "Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif",
      }}
    >
      <div
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage: `
            linear-gradient(rgba(34,211,238,0.075) 1px, transparent 1px),
            linear-gradient(90deg, rgba(34,211,238,0.075) 1px, transparent 1px),
            linear-gradient(rgba(250,204,21,0.038) 1px, transparent 1px),
            linear-gradient(90deg, rgba(250,204,21,0.038) 1px, transparent 1px)
          `,
          backgroundSize: "38px 38px, 38px 38px, 152px 152px, 152px 152px",
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          background: `
            radial-gradient(circle at 22% 18%, rgba(34,211,238,0.18), transparent 34%),
            radial-gradient(circle at 78% 72%, rgba(250,204,21,0.09), transparent 30%),
            linear-gradient(135deg, rgba(2,6,23,0.52), rgba(3,7,18,0.96))
          `,
        }}
      />

      <div
        style={{
          position: "absolute",
          left: 0,
          right: 0,
          top: `${scanY}%`,
          height: 2,
          background: `linear-gradient(90deg, transparent, ${primaryColor}, transparent)`,
          opacity: 0.28,
          filter: `drop-shadow(0 0 12px ${primaryColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          top: 0,
          bottom: 0,
          left: `${scanX}%`,
          width: 2,
          background: `linear-gradient(180deg, transparent, ${accentColor}, transparent)`,
          opacity: 0.16,
          filter: `drop-shadow(0 0 10px ${accentColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: framePadding * 0.45,
          border: `1px solid rgba(34,211,238,0.18)`,
          clipPath:
            "polygon(26px 0, calc(100% - 26px) 0, 100% 26px, 100% calc(100% - 26px), calc(100% - 26px) 100%, 26px 100%, 0 calc(100% - 26px), 0 26px)",
          opacity: entrance,
        }}
      />

      <div
        style={{
          position: "absolute",
          top: headerTop,
          left: framePadding,
          right: framePadding,
          display: "flex",
          justifyContent: "space-between",
          alignItems: "flex-start",
          gap: 24,
          opacity: entrance,
          transform: `translateY(${interpolate(entrance, [0, 1], [-18, 0])}px)`,
        }}
      >
        <div>
          <div
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: 10,
              padding: "8px 14px",
              background: "rgba(8,13,24,0.78)",
              border: `1px solid rgba(250,204,21,0.34)`,
              color: "rgba(255,255,255,0.76)",
              fontSize: isVertical ? 13 : 12,
              fontWeight: 850,
              letterSpacing: 2.4,
              textTransform: "uppercase",
              clipPath:
                "polygon(0 0, calc(100% - 12px) 0, 100% 12px, 100% 100%, 12px 100%, 0 calc(100% - 12px))",
            }}
          >
            <span
              style={{
                width: 8,
                height: 8,
                background: accentColor,
                boxShadow: `0 0 12px ${accentColor}`,
              }}
            />
            {panelLabel}
          </div>

          <h1
            style={{
              margin: "18px 0 7px",
              fontSize: titleSize,
              lineHeight: 0.96,
              fontWeight: 950,
              letterSpacing: -1.1,
              color: "white",
              textTransform: "uppercase",
              textShadow: `0 0 26px rgba(34,211,238,0.28)`,
            }}
          >
            {title}
          </h1>

          <p
            style={{
              margin: 0,
              maxWidth: isVertical ? width * 0.76 : width * 0.44,
              fontSize: subtitleSize,
              lineHeight: 1.34,
              color: "rgba(226,232,240,0.72)",
            }}
          >
            {subtitle}
          </p>
        </div>

        {!isVertical ? (
          <div
            style={{
              minWidth: 280,
              padding: "14px 16px",
              background: "rgba(8,13,24,0.68)",
              borderTop: `2px solid ${primaryColor}`,
              textAlign: "right",
            }}
          >
            <div
              style={{
                color: primaryColor,
                fontSize: 13,
                fontWeight: 900,
                letterSpacing: 2.8,
                textTransform: "uppercase",
              }}
            >
              {projectCode}
            </div>
            <div
              style={{
                marginTop: 8,
                color: "rgba(255,255,255,0.68)",
                fontSize: 15,
                letterSpacing: 1.6,
                textTransform: "uppercase",
              }}
            >
              {location}
            </div>
            <div
              style={{
                marginTop: 8,
                color: accentColor,
                fontSize: 12,
                fontWeight: 850,
                letterSpacing: 2,
                textTransform: "uppercase",
              }}
            >
              {statusText}
            </div>
          </div>
        ) : null}
      </div>

      <div
        style={{
          position: "absolute",
          left: framePadding,
          right: framePadding,
          top: isVertical ? height * 0.23 : height * 0.22,
          bottom: isVertical ? height * 0.08 : height * 0.08,
          display: "flex",
          gap: cardGap,
          opacity: entrance,
        }}
      >
        {columns.map((column, columnIndex) => (
          <div
            key={columnIndex}
            style={{
              flex: 1,
              display: "flex",
              flexDirection: "column",
              gap: cardGap,
            }}
          >
            {column.map((block, blockIndex) => {
              const delay = block.delay ?? blockIndex * 5 + columnIndex * 3;
              const cardSpring = spring({
                frame: Math.max(frame - delay, 0),
                fps,
                config: {
                  damping: 13,
                  stiffness: 105,
                  mass: 0.8,
                },
              });

              const cardAccent = block.accentColor ?? primaryColor;
              const heightPct = Math.max(28, Math.min(68, block.heightPct ?? 46));
              const cardScale = 0.92 + cardSpring * 0.08;
              const translateY = interpolate(cardSpring, [0, 1], [26, 0]);

              return (
                <div
                  key={`${columnIndex}-${blockIndex}`}
                  style={{
                    position: "relative",
                    height: `${heightPct}%`,
                    minHeight: isVertical ? 142 : 170,
                    overflow: "hidden",
                    background: `
                      linear-gradient(135deg, rgba(8,13,24,0.96), rgba(15,23,42,0.82)),
                      radial-gradient(circle at 20% 10%, rgba(34,211,238,0.16), transparent 36%)
                    `,
                    border: `1px solid rgba(34,211,238,0.24)`,
                    borderLeft: `3px solid ${cardAccent}`,
                    boxShadow: `
                      inset 0 0 34px rgba(34,211,238,0.055),
                      0 0 28px rgba(0,0,0,0.35)
                    `,
                    clipPath:
                      "polygon(0 0, calc(100% - 18px) 0, 100% 18px, 100% 100%, 18px 100%, 0 calc(100% - 18px))",
                    transform: `translateY(${translateY}px) scale(${cardScale})`,
                    opacity: cardSpring,
                  }}
                >
                  {block.imageUrl ? (
                    <Img
                      src={block.imageUrl}
                      style={{
                        position: "absolute",
                        inset: 0,
                        width: "100%",
                        height: "100%",
                        objectFit: "cover",
                        opacity: 0.24,
                        filter: "grayscale(1) contrast(1.25)",
                      }}
                    />
                  ) : null}

                  <div
                    style={{
                      position: "absolute",
                      inset: 0,
                      backgroundImage: `
                        linear-gradient(rgba(255,255,255,0.045) 1px, transparent 1px),
                        linear-gradient(90deg, rgba(255,255,255,0.045) 1px, transparent 1px)
                      `,
                      backgroundSize: "22px 22px",
                      opacity: 0.7,
                    }}
                  />

                  <div
                    style={{
                      position: "absolute",
                      inset: 0,
                      background: `linear-gradient(135deg, rgba(2,6,23,0.12), rgba(2,6,23,0.88))`,
                    }}
                  />

                  <div
                    style={{
                      position: "absolute",
                      top: 14,
                      left: 14,
                      right: 14,
                      display: "flex",
                      justifyContent: "space-between",
                      gap: 10,
                      alignItems: "center",
                    }}
                  >
                    <div
                      style={{
                        padding: "5px 8px",
                        border: `1px solid rgba(250,204,21,0.28)`,
                        color: accentColor,
                        background: "rgba(250,204,21,0.07)",
                        fontSize: isVertical ? 10 : 11,
                        fontWeight: 900,
                        letterSpacing: 1.6,
                        textTransform: "uppercase",
                      }}
                    >
                      {block.tag ?? panelLabel}
                    </div>

                    <div
                      style={{
                        width: 8,
                        height: 8,
                        background: cardAccent,
                        boxShadow: `0 0 12px ${cardAccent}`,
                      }}
                    />
                  </div>

                  <div
                    style={{
                      position: "absolute",
                      left: 16,
                      right: 16,
                      bottom: 16,
                    }}
                  >
                    <div
                      style={{
                        color: "white",
                        fontSize: isVertical ? 18 : 22,
                        lineHeight: 1,
                        fontWeight: 950,
                        letterSpacing: -0.5,
                        textTransform: "uppercase",
                        textShadow: `0 0 18px rgba(34,211,238,0.24)`,
                      }}
                    >
                      {block.title ?? title}
                    </div>

                    <div
                      style={{
                        marginTop: 7,
                        color: "rgba(226,232,240,0.68)",
                        fontSize: isVertical ? 12 : 14,
                        lineHeight: 1.2,
                        fontWeight: 650,
                      }}
                    >
                      {block.subtitle ?? subtitle}
                    </div>

                    <div
                      style={{
                        marginTop: 12,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "space-between",
                        gap: 10,
                      }}
                    >
                      <div
                        style={{
                          flex: 1,
                          height: 6,
                          background: "rgba(255,255,255,0.08)",
                          overflow: "hidden",
                        }}
                      >
                        <div
                          style={{
                            width: `${Math.max(
                              8,
                              Math.min(100, Number(String(block.metric ?? "75").replace("%", "")) || 75)
                            )}%`,
                            height: "100%",
                            background: `linear-gradient(90deg, ${primaryColor}, ${cardAccent})`,
                            boxShadow: `0 0 12px ${cardAccent}`,
                          }}
                        />
                      </div>

                      <div
                        style={{
                          color: cardAccent,
                          fontSize: isVertical ? 18 : 20,
                          fontWeight: 950,
                          lineHeight: 1,
                          minWidth: 52,
                          textAlign: "right",
                        }}
                      >
                        {block.metric ?? "75%"}
                      </div>
                    </div>
                  </div>

                  <div
                    style={{
                      position: "absolute",
                      top: 0,
                      right: 0,
                      width: 42,
                      height: 42,
                      borderTop: `2px solid ${cardAccent}`,
                      borderRight: `2px solid ${cardAccent}`,
                      opacity: 0.58,
                    }}
                  />

                  <div
                    style={{
                      position: "absolute",
                      bottom: 0,
                      left: 0,
                      width: 42,
                      height: 42,
                      borderBottom: `2px solid rgba(34,211,238,0.48)`,
                      borderLeft: `2px solid rgba(34,211,238,0.48)`,
                      opacity: 0.58,
                    }}
                  />
                </div>
              );
            })}
          </div>
        ))}
      </div>

      {isVertical ? (
        <div
          style={{
            position: "absolute",
            left: framePadding,
            right: framePadding,
            bottom: 32,
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            gap: 16,
            padding: "12px 14px",
            background: "rgba(8,13,24,0.78)",
            borderLeft: `3px solid ${accentColor}`,
            opacity: entrance,
          }}
        >
          <div>
            <div
              style={{
                color: primaryColor,
                fontSize: 12,
                fontWeight: 900,
                letterSpacing: 2.2,
                textTransform: "uppercase",
              }}
            >
              {projectCode}
            </div>
            <div
              style={{
                marginTop: 5,
                color: "rgba(255,255,255,0.68)",
                fontSize: 12,
                letterSpacing: 1.2,
                textTransform: "uppercase",
              }}
            >
              {location}
            </div>
          </div>

          <div
            style={{
              color: accentColor,
              fontSize: 12,
              fontWeight: 850,
              letterSpacing: 1.6,
              textTransform: "uppercase",
              textAlign: "right",
            }}
          >
            {statusText}
          </div>
        </div>
      ) : null}

      {[
        { top: 24, left: 24, borderWidth: "2px 0 0 2px" },
        { top: 24, right: 24, borderWidth: "2px 2px 0 0" },
        { bottom: 24, left: 24, borderWidth: "0 0 2px 2px" },
        { bottom: 24, right: 24, borderWidth: "0 2px 2px 0" },
      ].map((corner, index) => (
        <div
          key={index}
          style={{
            position: "absolute",
            width: 42,
            height: 42,
            borderStyle: "solid",
            borderColor: "rgba(34,211,238,0.55)",
            opacity: 0.78,
            ...corner,
          }}
        />
      ))}
    </AbsoluteFill>
  );
}

