  subtitle = "Galeria técnica de etapas estruturais",
  projectCode = "ENG-3084",
  statusText = "MONITORAMENTO ATIVO",
  location = "SETOR B / CANTEIRO 04",
  panelLabel = "STRUCTURAL GALLERY",
  blocks = defaultBlocks,
  primaryColor = "#22d3ee",
  secondaryColor = "#0f766e",
  accentColor = "#facc15",
