  const framePadding = isVertical ? 42 : 62;
  const headerTop = isVertical ? 48 : 42;
  const titleSize = isVertical ? width * 0.052 : height * 0.055;
  const subtitleSize = isVertical ? width * 0.03 : height * 0.028;
  const cardGap = isVertical ? 14 : 18;

  return (
    <AbsoluteFill
