                  />

                  <div
                    style={{
                      position: "absolute",
                      top: 14,
                      left: 14,
                      right: 14,
                      display: "flex",
                      justifyContent: "space-between",
                      gap: 10,
                      alignItems: "center",
                    }}
                  >
                    <div
                      style={{
                        padding: "5px 8px",
                        border: `1px solid rgba(250,204,21,0.28)`,
                        color: accentColor,
                        background: "rgba(250,204,21,0.07)",
                        fontSize: isVertical ? 10 : 11,
                        fontWeight: 900,
                        letterSpacing: 1.6,
                        textTransform: "uppercase",
                      }}
                    >
                      {block.tag ?? panelLabel}
                    </div>

                    <div
                      style={{
                        width: 8,
                        height: 8,
                        background: cardAccent,
                        boxShadow: `0 0 12px ${cardAccent}`,
                      }}
                    />
                  </div>

                  <div
                    style={{
                      position: "absolute",
                      left: 16,
                      right: 16,
                      bottom: 16,
                    }}
                  >
                    <div
                      style={{
                        color: "white",
                        fontSize: isVertical ? 18 : 22,
                        lineHeight: 1,
                        fontWeight: 950,
                        letterSpacing: -0.5,
                        textTransform: "uppercase",
                        textShadow: `0 0 18px rgba(34,211,238,0.24)`,
                      }}
                    >
                      {block.title ?? title}
                    </div>

                    <div
                      style={{
                        marginTop: 7,
                        color: "rgba(226,232,240,0.68)",
                        fontSize: isVertical ? 12 : 14,
                        lineHeight: 1.2,
                        fontWeight: 650,
                      }}
                    >
                      {block.subtitle ?? subtitle}
                    </div>

                    <div
                      style={{
                        marginTop: 12,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "space-between",
                        gap: 10,
                      }}
                    >
                      <div
                        style={{
                          flex: 1,
                          height: 6,
                          background: "rgba(255,255,255,0.08)",
                          overflow: "hidden",
                        }}
                      >
                        <div
                          style={{
                            width: `${Math.max(
                              8,
                              Math.min(100, Number(String(block.metric ?? "75").replace("%", "")) || 75)
                            )}%`,
                            height: "100%",
                            background: `linear-gradient(90deg, ${primaryColor}, ${cardAccent})`,
                            boxShadow: `0 0 12px ${cardAccent}`,
                          }}
                        />
                      </div>

                      <div
                        style={{
                          color: cardAccent,
                          fontSize: isVertical ? 18 : 20,
                          fontWeight: 950,
                          lineHeight: 1,
                          minWidth: 52,
                          textAlign: "right",
                        }}
                      >
                        {block.metric ?? "75%"}
                      </div>
                    </div>
                  </div>

                  <div
                    style={{
                      position: "absolute",
                      top: 0,
                      right: 0,
                      width: 42,
                      height: 42,
                      borderTop: `2px solid ${cardAccent}`,
                      borderRight: `2px solid ${cardAccent}`,
                      opacity: 0.58,
                    }}
                  />

                  <div
                    style={{
                      position: "absolute",
                      bottom: 0,
                      left: 0,
                      width: 42,
                      height: 42,
