        ))}
      </div>

      {isVertical ? (
        <div
          style={{
            position: "absolute",
            left: framePadding,
            right: framePadding,
            bottom: 32,
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            gap: 16,
            padding: "12px 14px",
            background: "rgba(8,13,24,0.78)",
            borderLeft: `3px solid ${accentColor}`,
            opacity: entrance,
          }}
        >
          <div>
            <div
              style={{
                color: primaryColor,
                fontSize: 12,
                fontWeight: 900,
                letterSpacing: 2.2,
                textTransform: "uppercase",
              }}
            >
              {projectCode}
            </div>
            <div
              style={{
                marginTop: 5,
                color: "rgba(255,255,255,0.68)",
                fontSize: 12,
                letterSpacing: 1.2,
                textTransform: "uppercase",
              }}
            >
              {location}
            </div>
          </div>

          <div
            style={{
              color: accentColor,
              fontSize: 12,
              fontWeight: 850,
              letterSpacing: 1.6,
              textTransform: "uppercase",
              textAlign: "right",
            }}
          >
            {statusText}
          </div>
        </div>
      ) : null}

      {[
        { top: 24, left: 24, borderWidth: "2px 0 0 2px" },
        { top: 24, right: 24, borderWidth: "2px 2px 0 0" },
        { bottom: 24, left: 24, borderWidth: "0 0 2px 2px" },
