"use client";

import React from "react";
import {
  AbsoluteFill,
  Img,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

type EngineeringZoomPulseProps = {
  imageUrl?: string;
  title?: string;
  subtitle?: string;
  projectCode?: string;
  statusText?: string;
  location?: string;
  panelLabel?: string;
  scanLabel?: string;
  duration?: number | string;
  minScale?: number | string;
  maxScale?: number | string;
  primaryColor?: string;
  secondaryColor?: string;
  accentColor?: string;
  backgroundColor?: string;
  overlayOpacity?: number | string;
};

const toNumber = (value: unknown, fallback: number) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
};

export const ZoomPulse: React.FC<EngineeringZoomPulseProps> = ({
  imageUrl = "https://images.pexels.com/photos/1726310/pexels-photo-1726310.jpeg?auto=compress&cs=tinysrgb&w=1260&h=750&dpr=2",
  title = "INSPEÇÃO ESTRUTURAL",
  subtitle = "Análise visual de campo com pulso técnico de aproximação",
  projectCode = "ENG-3074",
  statusText = "VARREDURA ATIVA",
  location = "SETOR C-08",
  panelLabel = "ZOOM PULSE",
  scanLabel = "FOCO TÉCNICO",
  duration = 4,
  minScale = 1,
  maxScale = 1.12,
  primaryColor = "#22d3ee",
  secondaryColor = "#0ea5e9",
  accentColor = "#facc15",
  backgroundColor = "#030712",
  overlayOpacity = 0.72,
}) => {
  const frame = useCurrentFrame();
  const { width, height, fps } = useVideoConfig();

  const isVertical = height > width;
  const pulseDurationFrames = Math.max(1, toNumber(duration, 4) * fps);
  const safeMinScale = toNumber(minScale, 1);
  const safeMaxScale = toNumber(maxScale, 1.12);
  const safeOverlayOpacity = Math.max(0, Math.min(1, toNumber(overlayOpacity, 0.72)));

  const cycle = (frame % pulseDurationFrames) / pulseDurationFrames;
  const wave = (1 - Math.cos(cycle * Math.PI * 2)) / 2;
  const imageScale = interpolate(wave, [0, 1], [safeMinScale, safeMaxScale]);

  const entrance = spring({
    frame,
    fps,
    config: {
      damping: 18,
      stiffness: 90,
      mass: 0.85,
    },
  });

  const scanY = interpolate(frame % 140, [0, 140], [-12, 112]);
  const scanX = interpolate(frame % 170, [0, 170], [-18, 118]);
  const reticleScale = interpolate(wave, [0, 1], [0.96, 1.08]);
  const reticleOpacity = interpolate(wave, [0, 1], [0.55, 0.95]);
  const rotatingAngle = (frame * 0.85) % 360;
  const reverseAngle = (frame * -0.45) % 360;

  const sidePadding = isVertical ? width * 0.07 : width * 0.045;
  const topPadding = isVertical ? height * 0.055 : height * 0.065;
  const titleSize = isVertical ? width * 0.062 : height * 0.07;
  const subtitleSize = isVertical ? width * 0.033 : height * 0.029;

  const frameInset = isVertical ? 34 : 48;
  const reticleSize = isVertical
    ? Math.min(width * 0.62, height * 0.32)
    : Math.min(width * 0.3, height * 0.48);

  return (
    <AbsoluteFill
      style={{
        backgroundColor,
        overflow: "hidden",
        color: "#e5f7ff",
        fontFamily:
          "Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif",
      }}
    >
      <Img
        src={imageUrl}
        style={{
          position: "absolute",
          inset: 0,
          width: "100%",
          height: "100%",
          objectFit: "cover",
          transform: `scale(${imageScale})`,
          filter: "contrast(1.12) saturate(0.72) brightness(0.78)",
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          background: `
            linear-gradient(90deg, rgba(3,7,18,0.92), rgba(3,7,18,${safeOverlayOpacity}) 44%, rgba(3,7,18,0.52)),
            radial-gradient(circle at ${isVertical ? "50% 52%" : "67% 54%"}, rgba(34,211,238,0.24), transparent 34%),
            radial-gradient(circle at 18% 86%, rgba(250,204,21,0.12), transparent 28%)
          `,
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage: `
            linear-gradient(rgba(34,211,238,0.08) 1px, transparent 1px),
            linear-gradient(90deg, rgba(34,211,238,0.08) 1px, transparent 1px),
            linear-gradient(rgba(250,204,21,0.04) 1px, transparent 1px),
            linear-gradient(90deg, rgba(250,204,21,0.04) 1px, transparent 1px)
          `,
          backgroundSize: "38px 38px, 38px 38px, 152px 152px, 152px 152px",
          opacity: 0.72,
          mixBlendMode: "screen",
        }}
      />

      <div
        style={{
          position: "absolute",
          left: 0,
          right: 0,
          top: `${scanY}%`,
          height: 2,
          background: `linear-gradient(90deg, transparent, ${primaryColor}, transparent)`,
          opacity: 0.42,
          filter: `drop-shadow(0 0 12px ${primaryColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          top: 0,
          bottom: 0,
          left: `${scanX}%`,
          width: 2,
          background: `linear-gradient(180deg, transparent, ${accentColor}, transparent)`,
          opacity: 0.22,
          filter: `drop-shadow(0 0 10px ${accentColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: frameInset,
          border: `1px solid rgba(34,211,238,0.34)`,
          clipPath:
            "polygon(28px 0, calc(100% - 28px) 0, 100% 28px, 100% calc(100% - 28px), calc(100% - 28px) 100%, 28px 100%, 0 calc(100% - 28px), 0 28px)",
          boxShadow: `
            inset 0 0 42px rgba(34,211,238,0.08),
            0 0 44px rgba(0,0,0,0.42)
          `,
          opacity: entrance,
        }}
      />

      <div
        style={{
          position: "absolute",
          top: topPadding,
          left: sidePadding,
          right: sidePadding,
          opacity: entrance,
          transform: `translateY(${interpolate(entrance, [0, 1], [-18, 0])}px)`,
        }}
      >
        <div
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 10,
            padding: "9px 15px",
